    }
    for(int r=0;r<4;r++){
        int m=4+r; // L
        for(int j=0;j<4;j++) src_for_dst[m][r*4+j] = r*4+((j+1)%4);
    }
    for(int r=0;r<4;r++){
        int m=8+r; // R
        for(int j=0;j<4;j++) src_for_dst[m][r*4+j] = r*4+((j+3)%4);
    }
