        int m=12+c; // U
        for(int i=0;i<4;i++) src_for_dst[m][i*4+c] = ((i+1)%4)*4+c;
    }
    for(int m=0;m<MOVES;m++){
        for(int mask=0; mask<65536; mask++){
            uint16_t out=0;
            for(int dst=0; dst<16; dst++) if(mask & (1u<<src_for_dst[m][dst])) out |= (1u<<dst);
            moved_mask[m][mask]=out;
        }
    }
}

void init_ways(){
    for(int pos=16; pos>=0; pos--) for(int a=0;a<=4;a++) for(int b=0;b<=4;b++) ways[pos][a][b]=0;
    ways[16][0][0]=1;
    for(int pos=15; pos>=0; pos--){
        for(int a=0;a<=4;a++) for(int b=0;b<=4;b++){
            int rem = 16-pos;
            (void)rem;
            int v = ways[pos+1][a][b];
            if(a>0) v += ways[pos+1][a-1][b];
            if(b>0) v += ways[pos+1][a][b-1];
            ways[pos][a][b]=v;
        }
    }
}

int rank_masks(uint16_t ma,uint16_t mb){
    int rank=0, a=4, b=4;
    for(int pos=0; pos<16; pos++){
        bool isA = (ma>>pos)&1u;
        bool isB = (mb>>pos)&1u;
        int sym = isA?1:(isB?2:0);
        if(sym>0) rank += ways[pos+1][a][b];
        if(sym>1) rank += ways[pos+1][a-1][b];
        if(sym==1) a--; else if(sym==2) b--;
    }
    return rank;
}

pair<uint16_t,uint16_t> masks_for_pair(uint32_t s,int ca,int cb){
    uint16_t ma=0, mb=0;
    for(int pos=0; pos<16; pos++){
        int v=cell(s,pos);
        if(v==ca) ma |= (1u<<pos);
        else if(v==cb) mb |= (1u<<pos);
    }
    return {ma,mb};
}

void build_pdb(){
    color_pairs.clear();
    for(int a=0;a<4;a++) for(int b=a+1;b<4;b++) color_pairs.push_back({a,b});
    pdb.assign(color_pairs.size(), vector<uint8_t>(ways[0][4][4], INF));

    for(size_t pi=0; pi<color_pairs.size(); pi++){
        auto [ca,cb] = color_pairs[pi];
        auto [tma,tmb] = masks_for_pair(target_state, ca, cb);
        int tr = rank_masks(tma,tmb);
        deque<uint32_t> q;
        uint32_t packed = uint32_t(tma) | (uint32_t(tmb)<<16);
        pdb[pi][tr]=0;
        q.push_back(packed);
        size_t seen=1;
        while(!q.empty()){
            uint32_t cur=q.front(); q.pop_front();
            uint16_t ma = cur & 0xFFFFu;
            uint16_t mb = cur >> 16;
            uint8_t d = pdb[pi][rank_masks(ma,mb)];
            for(int m=0;m<MOVES;m++){
                uint16_t na=apply_move_mask(ma,m), nb=apply_move_mask(mb,m);
                int nr=rank_masks(na,nb);
                if(pdb[pi][nr]==INF){
                    pdb[pi][nr]=d+1;
                    q.push_back(uint32_t(na) | (uint32_t(nb)<<16));
                    seen++;
                }
            }
        }
        cerr << "pair " << ca << cb << " seen " << seen << "\n";
    }
}

int heuristic(uint32_t s){
    int h=0;
    for(size_t pi=0; pi<color_pairs.size(); pi++){
        auto [ca,cb]=color_pairs[pi];
        auto [ma,mb]=masks_for_pair(s,ca,cb);
        h = max<int>(h, pdb[pi][rank_masks(ma,mb)]);
    }
    return h;
}

int next_bound;
unordered_map<uint32_t,uint8_t> best_depth;
vector<int> path;

bool dfs(uint32_t s,int g,int bound,int prev){
    int h=heuristic(s);
    int f=g+h;
    if(f>bound){ next_bound=min(next_bound,f); return false; }
    if(s==target_state) return true;
    auto it = best_depth.find(s);
    if(it!=best_depth.end() && it->second <= g) return false;
    best_depth[s]=g;
    for(int m=0;m<MOVES;m++){
        if(prev!=-1 && inverse_move[m]==prev) continue;
        uint32_t ns=apply_move_state(s,m);
        path.push_back(m);
        if(dfs(ns,g+1,bound,m)) return true;
        path.pop_back();
    }
    return false;
}

vector<int> solve(uint32_t start){
    path.clear();
    int bound=heuristic(start);
    while(true){
        best_depth.clear();
        next_bound=1e9;
        cerr << "bound " << bound << "\n";
        if(dfs(start,0,bound,-1)) return path;
        if(next_bound>=1e9) throw runtime_error("no solution");
        bound=next_bound;
    }
}

