        array<int,16>{3,1,3,2, 0,2,2,3, 0,1,3,0, 2,1,0,1},
        array<int,16>{2,1,3,2, 1,3,3,3, 0,1,0,0, 2,0,1,2}
    };
    for(size_t i=0;i<starts.size();i++){
        uint32_t s=pack_board(starts[i]);
        cerr << "start " << i+1 << " heuristic " << heuristic(s) << "\n";
        auto sol=solve(s);
        cout << "lock " << i+1 << " len " << sol.size() << ":";
        for(int m:sol) cout << ' ' << move_names[m];
        cout << '\n';
    }
}
