import json
from array import array


N = 4
MOD = 4
MOVE_NAMES = [
    "D0",
    "D1",
    "D2",
    "D3",
    "L0",
    "L1",
    "L2",
    "L3",
    "R0",
    "R1",
    "R2",
    "R3",
    "U0",
    "U1",
    "U2",
    "U3",
]
INVERSE_MOVE = [12, 13, 14, 15, 8, 9, 10, 11, 4, 5, 6, 7, 0, 1, 2, 3]
TARGET_NORMALIZED = [
    0, 3, 2, 1,
    3, 2, 1, 0,
    2, 1, 0, 3,
    1, 0, 3, 2,
]
COLOR_PAIRS = [(0, 1), (0, 2), (0, 3), (1, 2), (1, 3), (2, 3)]
PAIR_STATE_COUNT = 1820 * 495


def pack_board(values):
    state = 0
    for pos, value in enumerate(values):
        state |= (value & 3) << (2 * pos)
    return state


def unpack_board(state):
    return [(state >> (2 * pos)) & 3 for pos in range(16)]


TARGET_STATE = pack_board(TARGET_NORMALIZED)


def build_move_sources():
    src_for_dst = [list(range(16)) for _ in range(16)]

    for col in range(4):
        move = col
        for row in range(4):
            src_for_dst[move][((row + 1) % 4) * 4 + col] = row * 4 + col

    for row in range(4):
        move = 4 + row
        for col in range(4):
            src_for_dst[move][row * 4 + col] = row * 4 + ((col + 1) % 4)

    for row in range(4):
        move = 8 + row
        for col in range(4):
            src_for_dst[move][row * 4 + col] = row * 4 + ((col + 3) % 4)

    for col in range(4):
        move = 12 + col
        for row in range(4):
            src_for_dst[move][row * 4 + col] = ((row + 1) % 4) * 4 + col

    return src_for_dst


SRC_FOR_DST = build_move_sources()


def apply_move_state(state, move):
    out = 0
    mapping = SRC_FOR_DST[move]
    for dst in range(16):
        src = mapping[dst]
        out |= ((state >> (2 * src)) & 3) << (2 * dst)
    return out


def build_mask_moves():
    moved_masks = []
    for move in range(16):
        mapping = SRC_FOR_DST[move]
        table = array("H", [0]) * 65536
        for mask in range(65536):
            out = 0
            for dst in range(16):
                if (mask >> mapping[dst]) & 1:
                    out |= 1 << dst
            table[mask] = out
        moved_masks.append(table)
    return moved_masks


MOVED_MASKS = build_mask_moves()


def build_rank_tables():
    rank4of16 = array("I", [0xFFFFFFFF]) * 65536
    rank4of12 = array("I", [0xFFFFFFFF]) * 4096

    rank = 0
    for mask in range(65536):
        if mask.bit_count() == 4:
            rank4of16[mask] = rank
            rank += 1

    rank = 0
    for mask in range(4096):
        if mask.bit_count() == 4:
            rank4of12[mask] = rank
            rank += 1

    return rank4of16, rank4of12


RANK4OF16, RANK4OF12 = build_rank_tables()


def extract_pair_masks(state, first, second):
    first_mask = 0
    second_mask = 0
    for pos in range(16):
        value = (state >> (2 * pos)) & 3
        if value == first:
            first_mask |= 1 << pos
        elif value == second:
            second_mask |= 1 << pos
    return first_mask, second_mask


def pair_rank(first_mask, second_mask):
    compressed = 0
    next_bit = 1
    for pos in range(16):
        bit = 1 << pos
        if first_mask & bit:
            continue
        if second_mask & bit:
            compressed |= next_bit
        next_bit <<= 1
    return RANK4OF16[first_mask] * 495 + RANK4OF12[compressed]


def build_pair_tables():
    tables = []
    for first, second in COLOR_PAIRS:
        target_first, target_second = extract_pair_masks(TARGET_STATE, first, second)
        target_rank = pair_rank(target_first, target_second)

        dist = array("B", [255]) * PAIR_STATE_COUNT
        dist[target_rank] = 0

        queue = [target_first | (target_second << 16)]
        head = 0
        while head < len(queue):
            packed = queue[head]
            head += 1
            first_mask = packed & 0xFFFF
            second_mask = packed >> 16
            current_distance = dist[pair_rank(first_mask, second_mask)]

            for move in range(16):
                next_first = MOVED_MASKS[move][first_mask]
                next_second = MOVED_MASKS[move][second_mask]
                next_rank = pair_rank(next_first, next_second)
                if dist[next_rank] == 255:
                    dist[next_rank] = current_distance + 1
                    queue.append(next_first | (next_second << 16))

        tables.append(dist)

    return tables


PAIR_TABLES = build_pair_tables()


HEURISTIC_CACHE = {}


def heuristic(state):
    cached = HEURISTIC_CACHE.get(state)
    if cached is not None:
        return cached

    best = 0
    for table, (first, second) in zip(PAIR_TABLES, COLOR_PAIRS):
        first_mask, second_mask = extract_pair_masks(state, first, second)
        value = table[pair_rank(first_mask, second_mask)]
        if value > best:
