    active = {}

    for event in reversed(events):
        event_id = event["id"]
        is_active = event_id not in canceled_by_later_active_cancel
        active[event_id] = is_active
        if is_active and event["op"] == "cancel":
            canceled_by_later_active_cancel.add(event["target"])

    return [event for event in events if active[event["id"]]]


