            for col in range(event["left"], event["right"] + 1):
                board[row][col] = (board[row][col] + event["delta"]) % MOD
        return

    if op == "shift_row":
        row = event["row"]
        amount = event["amount"] % N
        if amount:
            board[row] = board[row][-amount:] + board[row][:-amount]
        return

    if op == "shift_col":
        col = event["col"]
        amount = event["amount"] % N
        if amount:
            values = [board[row][col] for row in range(N)]
            values = values[-amount:] + values[:-amount]
            for row in range(N):
                board[row][col] = values[row]
        return

    if op == "rotate":
        top = event["top"]
        left = event["left"]
        size = event["size"]
        turns = event["turns"] % 4
        block = [row[left:left + size] for row in board[top:top + size]]
