    current = [row[:] for row in board]

    for move in solution:
        axis = move[0]
        index = int(move[1])

        if axis == "R":
            row = [(value + 1) % MOD for value in current[index]]
            current[index] = row[-1:] + row[:-1]
        elif axis == "L":
